// Each flow that completes a distinct user state emits a DISTINCT event.
// Reusing a completion event name = cross-flow collision with no local error.

// WRONG: FLOW-02 emits 'OnboardingCompleted'
// → FLOW-08 (ListingDiscoveryEngine) receives a second event for same userId
// → creates a DUPLICATE listing feed for the user
// → no error anywhere in the system — observable only as duplicate data in FLOW-08

// CORRECT:
const PERSONALIZATION_COMPLETED_EVENT = 'PersonalizationCompleted' as const;
// ↑ MACHINE — string literal, never computed, never from config

await this.queue.enqueue(
  PERSONALIZATION_COMPLETED_EVENT,
  createCloudEvent({
    eventType: PERSONALIZATION_COMPLETED_EVENT,  // exact literal
    source:    'personalization-completion-service',
    tenantId:  input.tenantId,
    data: { tenantId, userId, feedId, profileId, personalizationCompletedAt },
    // Payload: NO PII — no questionnaire answers
  })
);

// FLOW-01 owns 'OnboardingCompleted' → FLOW-08 consumers
// FLOW-02 owns 'PersonalizationCompleted' → FLOW-03/04/05 consumers
// Two flows, two distinct events, two consumer sets — zero collision
